    55→    private static final String VERIFY_RUNNING_PROC = "SELECT " + "proc.pk_frame " + "FROM "
    56→            + "proc, " + "job " + "WHERE " + "proc.pk_job = job.pk_job " + "AND "
    57→            + "job.str_state = 'PENDING' " + "AND " + "proc.pk_proc= ? ";
