    59→    public boolean verifyRunningProc(String procId, String frameId) {
    60→        try {
    61→            String pk_frame =
    62→                    getJdbcTemplate().queryForObject(VERIFY_RUNNING_PROC, String.class, procId);
    63→            if (pk_frame != null) {
    64→                return pk_frame.equals(frameId);
    65→            } else {
    66→                return false;
    67→            }
    68→        } catch (org.springframework.dao.EmptyResultDataAccessException e) {
    69→            // EAT
    70→        }
    71→        return false;
    72→    }
