    77→    public boolean deleteVirtualProc(VirtualProc proc) {
    78→        if (getJdbcTemplate().update(DELETE_VIRTUAL_PROC, proc.getProcId()) == 0) {
    79→            logger.info("failed to delete " + proc + " , proc does not exist.");
    80→            return false;
    81→        }
    82→        // update all of the resource counts.
    83→        procDestroyed(proc);
    84→        return true;
    85→    }
