    87→    private static final String INSERT_VIRTUAL_PROC =
    88→            "INSERT INTO " + "proc " + "( " + "pk_proc, " + "pk_host, " + "pk_show, " + "pk_layer,"
    89→                    + "pk_job," + "pk_frame, " + "int_cores_reserved, " + "int_mem_reserved, "
    90→                    + "int_mem_pre_reserved, " + "int_mem_used, " + "int_gpus_reserved, "
    91→                    + "int_gpu_mem_reserved, " + "int_gpu_mem_pre_reserved, " + "int_gpu_mem_used, "
    92→                    + "b_local " + ") VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?) ";
