    94→    public void insertVirtualProc(VirtualProc proc) {
    95→        proc.id = SqlUtil.genKeyRandom();
    96→        long memReservedMin =
    97→                env.getRequiredProperty("dispatcher.memory.mem_reserved_min", Long.class);
    98→        long memGpuReservedMin =
    99→                env.getRequiredProperty("dispatcher.memory.mem_gpu_reserved_min", Long.class);
   100→        int result = 0;
   101→        try {
   102→            result = getJdbcTemplate().update(INSERT_VIRTUAL_PROC, proc.getProcId(),
   103→                    proc.getHostId(), proc.getShowId(), proc.getLayerId(), proc.getJobId(),
   104→                    proc.getFrameId(), proc.coresReserved, proc.memoryReserved, proc.memoryReserved,
   105→                    memReservedMin, proc.gpusReserved, proc.gpuMemoryReserved,
   106→                    proc.gpuMemoryReserved, memGpuReservedMin, proc.isLocalDispatch);
   107→
   108→            // Update all of the resource counts
   109→            procCreated(proc);
   110→        } catch (org.springframework.dao.DataIntegrityViolationException d) {
   111→            /*
   112→             * This means the frame is already running. If that is the case, don't delete it, just
   113→             * set pk_frame to null or the orphaned proc handler will catch it.
   114→             */
   115→            throw new ResourceDuplicationFailureException(
   116→                    "The frame " + proc.getFrameId() + " is already assigned to a proc.");
   117→        } catch (Exception e) {
   118→            String msg = "unable to book proc " + proc.getName() + " on frame " + proc.getFrameId()
   119→                    + " , " + e;
   120→            throw new ResourceReservationFailureException(msg, e);
   121→        }
   122→
   123→        if (result == 0) {
   124→            String msg =
   125→                    "unable to book proc " + proc.id + " the insert query succeeded but returned 0";
   126→            throw new ResourceReservationFailureException(msg);
   127→        }
   128→    }
