   130→    private static final String UPDATE_VIRTUAL_PROC_ASSIGN =
   131→            "UPDATE " + "proc " + "SET " + "pk_show = ?, " + "pk_job = ?, " + "pk_layer = ?, "
   132→                    + "pk_frame = ?, " + "int_mem_used = 0, " + "int_mem_max_used = 0, "
   133→                    + "int_virt_used = 0, " + "int_virt_max_used = 0, "
   134→                    + "ts_dispatched = current_timestamp " + "WHERE " + "pk_proc = ?";
   135→
   136→    public void updateVirtualProcAssignment(VirtualProc proc) {
   137→
   138→        int result = 0;
   139→        try {
   140→            result = getJdbcTemplate().update(UPDATE_VIRTUAL_PROC_ASSIGN, proc.getShowId(),
   141→                    proc.getJobId(), proc.getLayerId(), proc.getFrameId(), proc.getProcId());
   142→        } catch (org.springframework.dao.DataIntegrityViolationException d) {
   143→            throw new ResourceDuplicationFailureException("The frame " + proc.getFrameId()
   144→                    + " is already assigned to " + "the proc " + proc);
   145→        } catch (Exception e) {
   146→            String msg = "unable to book proc " + proc.id + ", " + e;
   147→            throw new ResourceReservationFailureException(msg, e);
   148→        }
   149→
   150→        /*
   151→         * If the proc was not updated then it has disappeared.
   152→         */
   153→        if (result == 0) {
   154→            String msg = "unable to book proc " + proc.id + ", the proc no longer exists,";
   155→            throw new ResourceReservationFailureException(msg);
   156→        }
   157→    }
