   174→    private static final String UPDATE_PROC_MEMORY_USAGE = "UPDATE " + "proc " + "SET "
   175→            + "int_mem_used = ?, " + "int_mem_max_used = ?," + "int_pss_used = ?, "
   176→            + "int_pss_max_used = ?, " + "int_virt_used = ?, " + "int_virt_max_used = ?, "
   177→            + "int_gpu_mem_used = ?, " + "int_gpu_mem_max_used = ?, " + "int_swap_used = ?, "
   178→            + "bytea_children = ?, " + "ts_ping = current_timestamp " + "WHERE " + "pk_frame = ?";
   179→
   180→    @Override
   181→    public void updateProcMemoryUsage(FrameInterface f, long rss, long maxRss, long pss,
   182→            long maxPss, long vss, long maxVss, long usedGpuMemory, long maxUsedGpuMemory,
   183→            long usedSwapMemory, byte[] children) {
   184→        /*
   185→         * This method is going to repeat for a proc every 1 minute, so if the proc is being touched
   186→         * by another thread, then return quietly without updating memory usage.
   187→         *
   188→         * If another thread is accessing the proc record, that means the proc is probably being
   189→         * booked to another frame, which makes this update invalid anyway.
   190→         */
   191→        try {
   192→            if (getJdbcTemplate()
   193→                    .queryForObject("SELECT pk_frame FROM proc WHERE pk_frame=? FOR UPDATE",
   194→                            String.class, f.getFrameId())
   195→                    .equals(f.getFrameId())) {
   196→
   197→                getJdbcTemplate().update(new PreparedStatementCreator() {
   198→                    @Override
   199→                    public PreparedStatement createPreparedStatement(Connection conn)
   200→                            throws SQLException {
   201→                        PreparedStatement updateProc =
   202→                                conn.prepareStatement(UPDATE_PROC_MEMORY_USAGE);
   203→                        updateProc.setLong(1, rss);
   204→                        updateProc.setLong(2, maxRss);
   205→                        updateProc.setLong(3, pss);
   206→                        updateProc.setLong(4, maxPss);
   207→                        updateProc.setLong(5, vss);
   208→                        updateProc.setLong(6, maxVss);
   209→                        updateProc.setLong(7, usedGpuMemory);
   210→                        updateProc.setLong(8, maxUsedGpuMemory);
   211→                        updateProc.setLong(9, usedSwapMemory);
   212→                        updateProc.setBytes(10, children);
   213→                        updateProc.setString(11, f.getFrameId());
   214→                        return updateProc;
   215→                    }
   216→                });
   217→            }
   218→        } catch (DataAccessException dae) {
   219→            logger.info("The proc for frame " + f + " could not be updated with new memory stats: "
   220→                    + dae);
   221→        }
   222→    }
