   228→        public VirtualProc mapRow(ResultSet rs, int rowNum) throws SQLException {
   229→            VirtualProc proc = new VirtualProc();
   230→            proc.id = rs.getString("pk_proc");
   231→            proc.hostId = rs.getString("pk_host");
   232→            proc.showId = rs.getString("pk_show");
   233→            proc.jobId = rs.getString("pk_job");
   234→            proc.layerId = rs.getString("pk_layer");
   235→            proc.frameId = rs.getString("pk_frame");
   236→            proc.hostName = rs.getString("host_name");
   237→            proc.allocationId = rs.getString("pk_alloc");
   238→            proc.facilityId = rs.getString("pk_facility");
   239→            proc.coresReserved = rs.getInt("int_cores_reserved");
   240→            proc.memoryReserved = rs.getLong("int_mem_reserved");
   241→            proc.memoryMax = rs.getLong("int_mem_max_used");
   242→            proc.gpusReserved = rs.getInt("int_gpus_reserved");
   243→            proc.gpuMemoryReserved = rs.getLong("int_gpu_mem_reserved");
   244→            proc.gpuMemoryMax = rs.getLong("int_gpu_mem_max_used");
   245→            proc.virtualMemoryMax = rs.getLong("int_virt_max_used");
   246→            proc.virtualMemoryUsed = rs.getLong("int_virt_used");
   247→            proc.memoryUsed = rs.getLong("int_mem_used");
   248→            proc.unbooked = rs.getBoolean("b_unbooked");
   249→            proc.isLocalDispatch = rs.getBoolean("b_local");
   250→            proc.os = rs.getString("str_os");
   251→            proc.childProcesses = rs.getBytes("bytea_children");
   252→            return proc;
   253→        }
   254→    };
