   446→    public boolean balanceUnderUtilizedProcs(ProcInterface targetProc, long targetMem) {
   447→
   448→        List<Map<String, Object>> result = getJdbcTemplate().queryForList(FIND_UNDERUTILIZED_PROCS,
   449→                targetProc.getHostId(), targetProc.getProcId());
   450→
   451→        if (result.size() == 0) {
   452→            logger.info("unable to find under utilized procs on host " + targetProc.getName());
   453→            return false;
   454→        }
   455→
   456→        final Map<String, Long> borrowMap = new HashMap<String, Long>(result.size());
   457→        for (Map<String, Object> map : result) {
   458→            logger.info("creating borrow map for: " + (String) map.get("pk_proc"));
   459→            borrowMap.put((String) map.get("pk_proc"), 0l);
   460→        }
   461→
   462→        long memBorrowedTotal = 0l;
   463→        int pass = 0;
   464→        int maxPasses = 3;
   465→
   466→        while (true) {
   467→            // the amount of memory we're going to borrow per frame/proc
   468→            long memPerFrame = ((targetMem - memBorrowedTotal) / result.size()) + 1;
   469→
   470→            // loop through all of our other running frames and try to borrow
   471→            // a little bit of memory from each one.
   472→            for (Map<String, Object> map : result) {
   473→                String pk_proc = (String) map.get("pk_proc");
   474→                Long free_mem = (Long) map.get("free_mem");
   475→                long memReservedMin =
   476→                        env.getRequiredProperty("dispatcher.memory.mem_reserved_min", Long.class);
   477→                long available = free_mem - borrowMap.get(pk_proc) - memReservedMin;
   478→                if (available > memPerFrame) {
   479→                    borrowMap.put(pk_proc, borrowMap.get(pk_proc) + memPerFrame);
   480→                    memBorrowedTotal = memBorrowedTotal + memPerFrame;
   481→                }
   482→            }
   483→            pass++;
   484→
   485→            // If we were unable to borrow anything, just break
   486→            if (memBorrowedTotal == 0) {
   487→                break;
   488→            }
   489→            // If we got the memory we needed, break
   490→            if (memBorrowedTotal >= targetMem) {
   491→                break;
   492→            }
   493→            // If we've exceeded the number of tries in this loop, break
   494→            if (pass >= maxPasses) {
   495→                break;
   496→            }
   497→        }
   498→
   499→        logger.info("attempted to borrow " + targetMem + " for host " + targetProc.getName()
   500→                + ", obtained " + memBorrowedTotal);
   501→
   502→        if (memBorrowedTotal < targetMem) {
   503→            logger.info("mem borrowed " + memBorrowedTotal + " was less than the target memory of "
   504→                    + targetMem);
   505→            return false;
   506→        }
   507→
   508→        /*
   509→         * This might fail... I'm not really sure if we should fail the whole operation or what.
   510→         * Just gonna let it ride for now.
   511→         */
   512→        for (Map.Entry<String, Long> set : borrowMap.entrySet()) {
   513→            int success = getJdbcTemplate().update(
   514→                    "UPDATE proc SET int_mem_reserved = int_mem_reserved - ? WHERE pk_proc=?",
   515→                    set.getValue(), set.getKey());
   516→            logger.info("transfering " + (set.getValue() * success) + " from " + set.getKey());
   517→        }
   518→
   519→        return true;
   520→    }
