   319→    @Override
   320→    public void insertRenderHost(RenderHost host, AllocationInterface a, boolean useLongNames) {
   321→
   322→        ThreadMode threadMode = ThreadMode.AUTO;
   323→        if (host.getNimbyEnabled()) {
   324→            threadMode = ThreadMode.ALL;
   325→        }
   326→
   327→        long memUnits = convertMemoryUnits(host);
   328→        long memReserverMin =
   329→                env.getRequiredProperty("dispatcher.memory.mem_reserved_min", Long.class);
   330→        if (memUnits < memReserverMin) {
   331→            throw new EntityCreationError("could not create host " + host.getName() + ", "
   332→                    + " must have at least " + memReserverMin + " free memory.");
   333→        }
   334→
   335→        String fqdn;
   336→        String name = host.getName();
   337→        try {
   338→            fqdn = InetAddress.getByName(host.getName()).getCanonicalHostName();
   339→            // If the provided host name matches the pinged name, use the pinged name.
   340→            // Otherwise use the provided name.
   341→            // If the host lookup fails, use the provided name.
   342→            // In all cases attempt to strip off the domain when setting the name.
   343→            if (fqdn.equals(host.getName())) {
   344→                name = getHostNameFromFQDN(fqdn, useLongNames);
   345→            } else {
   346→                name = getHostNameFromFQDN(host.getName(), useLongNames);
   347→                fqdn = host.getName();
   348→            }
   349→        } catch (UnknownHostException e) {
   350→            logger.info(e);
   351→            fqdn = host.getName();
   352→            name = getHostNameFromFQDN(name, useLongNames);
   353→        }
   354→
   355→        String hid = SqlUtil.genKeyRandom();
   356→        int coreUnits = host.getNumProcs() * host.getCoresPerProc();
   357→        String os = host.getAttributesMap().get("SP_OS");
   358→        if (os == null) {
   359→            os = Dispatcher.OS_DEFAULT;
   360→        }
   361→
   362→        getJdbcTemplate().update(INSERT_HOST_DETAIL[0], hid, a.getAllocationId(), name,
   363→                host.getNimbyEnabled(), LockState.OPEN.toString(), host.getNumProcs(), coreUnits,
   364→                coreUnits, memUnits, memUnits, host.getNumGpus(), host.getNumGpus(),
   365→                host.getTotalGpuMem(), host.getTotalGpuMem(), fqdn, threadMode.getNumber());
   366→
   367→        getJdbcTemplate().update(INSERT_HOST_DETAIL[1], hid, hid, host.getTotalMem(),
   368→                host.getFreeMem(), host.getTotalGpuMem(), host.getFreeGpuMem(), host.getTotalSwap(),
   369→                host.getFreeSwap(), host.getTotalMcp(), host.getFreeMcp(), host.getLoad(),
   370→                new Timestamp(host.getBootTime() * 1000l), host.getState().toString(), os);
   371→    }
