   631→    /**
   632→     * Checks if the passed in name looks like a fully qualified domain name. If so, returns the
   633→     * hostname without the domain. Otherwise returns the passed in name unchanged.
   634→     * 
   635→     * @param fqdn - String
   636→     * @return String - hostname
   637→     */
   638→    private String getHostNameFromFQDN(String fqdn, Boolean useLongNames) {
   639→        String hostName;
   640→        Pattern ipPattern = Pattern.compile("^(?:[0-9]{1,3}\\.){3}[0-9]{1,3}$");
   641→        Matcher ipMatcher = ipPattern.matcher(fqdn);
   642→        if (ipMatcher.matches()) {
   643→            hostName = fqdn;
   644→        } else if (fqdn.contains(":")) {
   645→            // looks like IPv6 address.
   646→            hostName = fqdn;
   647→        } else if (useLongNames) {
   648→            hostName = fqdn;
   649→            Pattern domainPattern = Pattern
   650→                    .compile(".*(\\.(.*)\\.(co(m|.[a-z]{2})|biz|edu|info|net|org|cn|de|eu|nl))$");
   651→            Matcher domainMatcher = domainPattern.matcher(fqdn);
   652→            if (domainMatcher.matches()) {
   653→                hostName = fqdn.replace(domainMatcher.group(1), "");
   654→            }
   655→        } else {
   656→            hostName = fqdn.split("\\.")[0];
   657→        }
   658→        return hostName;
   659→
   660→    }
