   662→    /**
   663→     * Converts the amount of memory reported by the machine to a modificed value which takes into
   664→     * account the operating system and the possibility of user applications.
   665→     *
   666→     * @param host
   667→     * @return
   668→     */
   669→    private long convertMemoryUnits(RenderHost host) {
   670→
   671→        long memUnits;
   672→        if (host.getTagsList().contains("64bit")) {
   673→            memUnits = CueUtil.convertKbToFakeKb64bit(env, host.getTotalMem());
   674→        } else {
   675→            memUnits = CueUtil.convertKbToFakeKb32bit(env, host.getTotalMem());
   676→        }
   677→
   678→        /*
   679→         * If this is a desktop, we'll just cut the memory so we don't annoy the user.
   680→         */
   681→        if (host.getNimbyEnabled()) {
   682→            long memReservedSystem =
   683→                    env.getRequiredProperty("dispatcher.memory.mem_reserved_system", Long.class);
   684→            memUnits = (long) (memUnits / 1.5) + memReservedSystem;
   685→        }
   686→
   687→        return memUnits;
   688→    }
