   271→    private static final String BALANCE_MEM =
   272→            "UPDATE " + "layer " + "SET " + "int_mem_min = ? " + "WHERE " + "pk_layer = ? " + "AND "
   273→                    + "int_mem_min > ? " + "AND " + "b_optimize = true";
