   275→    @Override
   276→    public boolean balanceLayerMinMemory(LayerInterface layer, long frameMaxRss) {
   277→
   278→        /**
   279→         * Lowers the memory value on the frame when the maxrss is lower than the memory
   280→         * requirement.
   281→         */
   282→        long maxrss = getJdbcTemplate().queryForObject(
   283→                "SELECT int_max_rss FROM layer_mem WHERE pk_layer=?", Long.class,
   284→                layer.getLayerId());
   285→
   286→        if (maxrss < frameMaxRss) {
   287→            maxrss = frameMaxRss;
   288→        }
   289→        if (maxrss < MEM_RESERVED_MIN) {
   290→            maxrss = MEM_RESERVED_MIN;
   291→        } else {
   292→            maxrss = maxrss + CueUtil.MB256;
   293→        }
   294→
   295→        boolean result =
   296→                getJdbcTemplate().update(BALANCE_MEM, maxrss, layer.getLayerId(), maxrss) == 1;
   297→        if (result) {
   298→            logger.info(layer.getName() + " was balanced to " + maxrss);
   299→        }
   300→        return result;
   301→    }
