   376→    @Override
   377→    public void updateLayerTags(LayerInterface layer, Set<String> tags) {
   378→        if (tags.size() == 0) {
   379→            throw new IllegalArgumentException("Layers must have at least one tag.");
   380→        }
   381→        StringBuilder sb = new StringBuilder(128);
   382→        for (String t : tags) {
   383→            if (t == null) {
   384→                continue;
   385→            }
   386→            if (t.length() < 1) {
   387→                continue;
   388→            }
   389→            sb.append(t + " | ");
   390→        }
   391→        sb.delete(sb.length() - 3, sb.length());
   392→        if (sb.length() == 0) {
   393→            throw new IllegalArgumentException(
   394→                    "Invalid layer tags, cannot contain null tags or " + "tags of zero length.");
   395→        }
   396→        getJdbcTemplate().update("UPDATE layer SET str_tags=? WHERE pk_layer=?", sb.toString(),
   397→                layer.getLayerId());
   398→    }
