   301→                    "UPDATE host SET int_gpus_idle = int_gpus_idle + ? WHERE pk_host = ?", gpus,
   302→                    h.getHostId()) > 0;
   303→        } catch (DataAccessException e) {
   304→            throw new ResourceReservationFailureException(
   305→                    "Failed to de-allocate " + gpus + " GPU from host, " + e);
   306→        }
   307→    }
