   309→    @Override
   310→    public boolean hasResourceDeficit(HostInterface host) {
   311→        return getJdbcTemplate().queryForObject("SELECT COUNT(1) FROM host_local WHERE "
   312→                + "(int_cores_max < int_cores_max - int_cores_idle OR "
   313→                + "int_gpus_max < int_gpus_max - int_gpus_idle OR "
   314→                + "int_gpu_mem_max < int_gpu_mem_max - int_gpu_mem_idle OR "
   315→                + "int_mem_max < int_mem_max - int_mem_idle) AND " + "host_local.pk_host= ?",
   316→                Integer.class, host.getHostId()) > 0;
