   127→    @Autowired
   128→    public DispatcherDaoJdbc(Environment env) {
   129→        this.schedulingMode = SchedulingMode.valueOf(
   130→                env.getProperty("dispatcher.scheduling_mode", String.class, "PRIORITY_ONLY"));
   131→
   132→        // Parse the exclusion list from environment variable
   133→        // Expected format: "show1:allocation1,show2:allocation2"
   134→        String exclusionListStr = env.getProperty("dispatcher.exclusion_list", String.class, "");
   135→        this.exclusionShowAllocs = new LinkedHashSet<String>();
   136→        this.exclusionShows = new LinkedHashSet<String>();
   137→        if (!exclusionListStr.isEmpty()) {
   138→            for (String item : exclusionListStr.split(",")) {
   139→                String trimmedItem = item.trim();
   140→                if (!trimmedItem.isEmpty()) {
   141→                    if (trimmedItem.contains(":")) {
   142→                        this.exclusionShowAllocs.add(trimmedItem);
   143→                    } else {
   144→                        this.exclusionShows.add(trimmedItem);
   145→                    }
   146→                }
   147→            }
   148→        }
   149→    }
