   161→    /**
   162→     * Returns a sorted list of shows that have pending jobs which could benefit from the specified
   163→     * allocation.
   164→     *
   165→     * @param alloc
   166→     * @return a sorted list of shows.
   167→     */
   168→    private List<SortableShow> getBookableShows(AllocationInterface alloc) {
   169→        long startTime = System.currentTimeMillis();
   170→        String key = alloc.getAllocationId();
   171→
   172→        ShowCache cached = bookableShows.get(key);
   173→        if (cached == null) {
   174→            bookableShows.put(key, new ShowCache(
   175→                    getJdbcTemplate().query(FIND_SHOWS, SHOW_MAPPER, alloc.getAllocationId())));
   176→        } else if (cached.isExpired()) {
   177→            bookableShows.put(key, new ShowCache(
   178→                    getJdbcTemplate().query(FIND_SHOWS, SHOW_MAPPER, alloc.getAllocationId())));
   179→        }
   180→        prometheusMetrics.setBookingDurationMetric("getBookableShows",
   181→                System.currentTimeMillis() - startTime);
   182→
   183→        return bookableShows.get(key).shows;
   184→    }
   185→
   186→    private String handleInClause(String key, String query, int inValueLength) {
   187→        String placeholders = String.join(",", Collections.nCopies(inValueLength, "?"));
   188→        return query.replace(key + " IN ?", key + " IN (" + placeholders + ")");
   189→    }
