   191→    private Set<String> findDispatchJobs(DispatchHost host, int numJobs, boolean shuffleShows) {
   192→        LinkedHashSet<String> result = new LinkedHashSet<String>();
   193→        List<SortableShow> shows = new LinkedList<SortableShow>(getBookableShows(host));
   194→        // shows were sorted. If we want it in random sequence, we need to shuffle it.
   195→        if (shuffleShows) {
   196→            if (!shows.isEmpty())
   197→                shows.remove(0);
   198→            Collections.shuffle(shows);
   199→        }
   200→
   201→        long loopTime = System.currentTimeMillis();
   202→        // Filter out shows/allocs that are being dispatched by the new scheduler
   203→        // A list of show_name:alloc_name is read from the env to define which jobs
   204→        // should not be dispatched by Cuebot's dispatcher
   205→        for (SortableShow s : shows) {
   206→            long lastTime = System.currentTimeMillis();
   207→            String showName = s.getShowName();
   208→
   209→            // Check if this show:allocation combination is in the exclusion list
   210→            if (!exclusionShows.isEmpty()) {
   211→                if (exclusionShows.contains(showName)) {
   212→                    logger.info("skipping show " + showName + " entirely due to exclusion list");
   213→                    continue;
   214→                }
   215→            }
   216→
   217→            // Check if this show is in the exclusion list
   218→            if (!exclusionShowAllocs.isEmpty()) {
   219→                String exclusionKey = showName + ":" + host.allocationName;
   220→                if (exclusionShowAllocs.contains(exclusionKey)) {
   221→                    logger.info("skipping show " + showName + " on allocation "
   222→                            + host.allocationName + " due to exclusion list");
   223→                    continue;
   224→                }
   225→            }
   226→
   227→            if (s.isSkipped(host.tags, (long) host.cores, host.memory)) {
   228→                logger.info("skipping show " + s.getShowId());
   229→                continue;
   230→            }
   231→
   232→            if (s.isSkipped(host)) {
   233→                logger.info("skipping show " + s.getShowId() + ", over its subscription.");
   234→                continue;
   235→            }
   236→
   237→            /**
   238→             * Check if the show is over its subscription because we're using cached SortableShows,
   239→             * we don't pull a fresh list of shows for a while. If the show is over its subscription
   240→             * the alloc gets add to the SortableShow skipped alloc set.
   241→             */
   242→            if (getJdbcTemplate().queryForObject(
   243→                    "SELECT int_burst - int_cores FROM subscription WHERE pk_show=? AND pk_alloc=?",
   244→                    Integer.class, s.getShowId(), host.getAllocationId()) < 100) {
   245→                s.skip(host);
   246→
   247→                prometheusMetrics.setBookingDurationMetric("findDispatchJobs check overburst",
   248→                        System.currentTimeMillis() - lastTime);
   249→                continue;
   250→            }
   251→
   252→            if (host.idleGpus == 0 && (schedulingMode == SchedulingMode.BALANCED)) {
   253→                result.addAll(getJdbcTemplate().query(new PreparedStatementCreator() {
   254→                    @Override
   255→                    public PreparedStatement createPreparedStatement(Connection conn)
   256→                            throws SQLException {
   257→                        String query = handleInClause("str_os", FIND_JOBS_BY_SHOW_NO_GPU,
   258→                                host.getOs().length);
   259→                        PreparedStatement find_jobs_stmt = conn.prepareStatement(query);
   260→
   261→                        int index = 1;
   262→                        find_jobs_stmt.setString(index++, s.getShowId());
   263→                        find_jobs_stmt.setString(index++, host.getFacilityId());
   264→                        for (String item : host.getOs()) {
   265→                            find_jobs_stmt.setString(index++, item);
   266→                        }
   267→                        find_jobs_stmt.setInt(index++, host.idleCores);
   268→                        find_jobs_stmt.setLong(index++, host.idleMemory);
   269→                        find_jobs_stmt.setInt(index++, threadMode(host.threadMode));
   270→                        find_jobs_stmt.setString(index++, host.getName());
   271→                        find_jobs_stmt.setInt(index++, numJobs * 10);
   272→                        return find_jobs_stmt;
   273→                    }
   274→                }, PKJOB_MAPPER));
   275→                prometheusMetrics.setBookingDurationMetric("findDispatchJobs nogpu findByShowQuery",
   276→                        System.currentTimeMillis() - lastTime);
   277→            } else {
   278→                result.addAll(getJdbcTemplate().query(new PreparedStatementCreator() {
   279→                    @Override
   280→                    public PreparedStatement createPreparedStatement(Connection conn)
   281→                            throws SQLException {
   282→                        String query =
   283→                                handleInClause("str_os", findByShowQuery(), host.getOs().length);
   284→                        PreparedStatement find_jobs_stmt = conn.prepareStatement(query);
   285→                        int index = 1;
   286→                        find_jobs_stmt.setString(index++, s.getShowId());
   287→                        find_jobs_stmt.setString(index++, host.getFacilityId());
   288→                        for (String item : host.getOs()) {
   289→                            find_jobs_stmt.setString(index++, item);
   290→                        }
   291→                        find_jobs_stmt.setInt(index++, host.idleCores);
   292→                        find_jobs_stmt.setLong(index++, host.idleMemory);
   293→                        find_jobs_stmt.setInt(index++, threadMode(host.threadMode));
   294→                        find_jobs_stmt.setInt(index++, host.idleGpus);
   295→                        find_jobs_stmt.setLong(index++, (host.idleGpuMemory > 0) ? 1 : 0);
   296→                        find_jobs_stmt.setLong(index++, host.idleGpuMemory);
   297→                        find_jobs_stmt.setString(index++, host.getName());
   298→                        find_jobs_stmt.setInt(index++, numJobs * 10);
   299→                        return find_jobs_stmt;
   300→                    }
   301→                }, PKJOB_MAPPER));
   302→                prometheusMetrics.setBookingDurationMetric("findDispatchJobs findByShowQuery",
   303→                        System.currentTimeMillis() - lastTime);
   304→            }
   305→
   306→            // Collect metrics
   307→            prometheusMetrics.incrementFindJobsByShowQueryCountMetric();
   308→            if (result.size() < 1) {
   309→                if (host.gpuMemory == 0) {
   310→                    s.skip(host.tags, host.idleCores, host.idleMemory);
   311→                }
   312→            } else {
   313→                return result;
   314→            }
   315→        }
   316→        prometheusMetrics.setBookingDurationMetric("findDispatchJobs show loop",
   317→                System.currentTimeMillis() - loopTime);
   318→        return result;
   319→
   320→    }
