    30→/// Singleton getter for the RQD dispatcher service
    31→///
    32→/// Creates and returns a singleton instance of the RqdDispatcherService actor.
    33→/// The service is initialized with configuration from CONFIG on first access.
    34→///
    35→/// # Usage Example
    36→/// ```rust,ignore
    37→/// use crate::pipeline::dispatcher::{rqd_dispatcher_service, messages::DispatchLayer};
    38→/// use crate::models::{DispatchLayer as ModelDispatchLayer, Host};
    39→///
    40→/// async fn dispatch_example() -> miette::Result<()> {
    41→///     let dispatcher = rqd_dispatcher_service().await?;
    42→///
    43→///     let message = DispatchLayer {
    44→///         layer: my_layer,
    45→///         host: my_host,
    46→///         transaction_id: "tx-123".to_string(),
    47→///     };
    48→///
    49→///     match dispatcher.send(message).await {
    50→///         Ok(Ok(result)) => {
    51→///             println!("Dispatched {} frames", result.dispatched_frames.len());
    52→///         }
    53→///         Ok(Err(e)) => println!("Dispatch error: {}", e),
    54→///         Err(e) => println!("Actor mailbox error: {}", e),
    55→///     }
    56→///
    57→///     Ok(())
    58→/// }
    59→/// ```
    60→pub async fn rqd_dispatcher_service() -> Result<Addr<RqdDispatcherService>, miette::Error> {
    61→    RQD_DISPATCHER
    62→        .get_or_try_init(|| async {
    63→            use crate::{
    64→                config::CONFIG,
    65→                dao::{FrameDao, HostDao},
    66→            };
    67→
    68→            let frame_dao = Arc::new(FrameDao::new().await?);
    69→            let layer_dao = Arc::new(LayerDao::new().await?);
    70→            let host_dao = Arc::new(HostDao::new().await?);
    71→            let proc_dao = Arc::new(ProcDao::new().await?);
    72→
    73→            let service = RqdDispatcherService::new(
    74→                frame_dao,
    75→                layer_dao,
    76→                host_dao,
    77→                proc_dao,
    78→                CONFIG.rqd.dry_run_mode,
    79→            )
    80→            .await?;
    81→
    82→            Ok(service.start())
    83→        })
    84→        .await
    85→        .cloned()
    86→}
