    43→/// Actor wrapper for RqdDispatcher that provides message-based dispatch operations.
    44→///
    45→/// This actor handles:
    46→/// - Message-driven frame dispatching with proper error isolation
    47→/// - gRPC connection management and pooling
    48→/// - Database transaction coordination
    49→/// - Supervision and retry logic for external service failures
    50→#[derive(Clone)]
    51→pub struct RqdDispatcherService {
    52→    frame_dao: Arc<FrameDao>,
    53→    layer_dao: Arc<LayerDao>,
    54→    host_dao: Arc<HostDao>,
    55→    proc_dao: Arc<ProcDao>,
    56→    rqd_connection_cache: Cache<String, RqdInterfaceClient<Channel>>,
    57→    dry_run_mode: bool,
    58→}
