    71→
    72→impl Handler<DispatchLayerMessage> for RqdDispatcherService {
    73→    type Result = ResponseActFuture<Self, Result<DispatchResult, DispatchError>>;
    74→
    75→    fn handle(&mut self, msg: DispatchLayerMessage, _ctx: &mut Self::Context) -> Self::Result {
    76→        let DispatchLayerMessage { layer, host } = msg;
    77→
    78→        let dispatcher = self.clone();
    79→        debug!(
    80→            "Received dispatch message for layer {} on host {}",
    81→            layer.layer_name, host.name
    82→        );
    83→
    84→        Box::pin(
    85→            async move {
    86→                // Note: In a real implementation, we would need to coordinate with a transaction manager
    87→                // or pass the transaction through the message. For now, we'll create a new transaction
    88→                // within the dispatcher's database operations.
    89→
    90→                // Create a database transaction scope
    91→                let mut transaction = begin_transaction()
    92→                    .await
    93→                    .map_err(DispatchError::DbFailure)?;
    94→
    95→                match dispatcher.dispatch(&layer, host, &mut transaction).await {
    96→                    Ok((updated_host, updated_layer)) => {
    97→                        // Commit the transaction
    98→                        transaction
    99→                            .commit()
   100→                            .await
   101→                            .map_err(DispatchError::DbFailure)?;
   102→
   103→                        Ok(DispatchResult {
   104→                            updated_host,
   105→                            updated_layer,
   106→                        })
   107→                    }
   108→                    Err(e) => {
   109→                        // Rollback the transaction on error
   110→                        if let Err(rollback_err) = transaction.rollback().await {
   111→                            error!("Failed to rollback transaction: {}", rollback_err);
   112→                        }
   113→                        Err(e)
   114→                    }
   115→                }
   116→            }
   117→            .into_actor(self)
   118→            .map(|result, _actor, _ctx| result),
   119→        )
   120→    }
   121→}
