   155→
   156→    /// Dispatches a layer to a specific host with proper locking and error handling.
   157→    ///
   158→    /// The dispatch process:
   159→    /// 1. Acquires an exclusive lock on the target host
   160→    /// 2. Performs the actual dispatch operation
   161→    /// 3. Ensures the host lock is always released, even on panic or failure
   162→    ///
   163→    /// # Arguments
   164→    /// * `layer` - The layer containing frames to dispatch
   165→    /// * `host` - The target host for frame execution
   166→    ///
   167→    /// # Returns
   168→    /// * `Ok(())` on successful dispatch
   169→    /// * `Err(DispatchError)` on various failure conditions
   170→    async fn dispatch(
   171→        &self,
   172→        layer: &DispatchLayer,
   173→        host: Host,
   174→        transaction: &mut Transaction<'_, Postgres>,
   175→    ) -> Result<(Host, DispatchLayer), DispatchError> {
   176→        let host_id = host.id;
   177→        let host_disp = format!("{}", &host);
   178→        let layer_disp = format!("{}", &layer);
   179→
   180→        // Acquire lock first
   181→        if !self
   182→            .host_dao
   183→            .lock(transaction, &host.id)
   184→            .await
   185→            .map_err(DispatchError::Failure)?
   186→        {
   187→            return Err(DispatchError::HostLock(host.name.clone()));
   188→        }
   189→
   190→        // Ensure unlock is always called, regardless of panics or fails
   191→        let result = std::panic::AssertUnwindSafe(self.dispatch_inner(layer, host))
   192→            .catch_unwind()
   193→            .await;
   194→
   195→        // Always attempt to unlock, regardless of outcome. Failing to unlock here can be ignored as
   196→        // endint the transaction will automatically unlock.
   197→        if let Err(unlock_err) = self.host_dao.unlock(transaction, &host_id).await {
   198→            trace!("Failed to unlock host {}: {}", host_disp, unlock_err);
   199→        }
   200→
   201→        // Handle the result from dispatch_inner
   202→        match result {
   203→            Ok(result) => {
   204→                if result.is_ok() {
   205→                    info!(
   206→                        "Successfully dispatched layer {} on {}.",
   207→                        layer_disp, host_disp
   208→                    );
   209→                }
   210→                result
   211→            }
   212→            Err(_panic) => Err(DispatchError::Failure(miette!(
   213→                "Dispatch operation panicked for layer {} on host {}",
   214→                layer_disp,
   215→                host_id
   216→            ))),
   217→        }
   218→    }
   219→
   220→    async fn dispatch_inner(
   221→        &self,
   222→        layer: &DispatchLayer,
   223→        host: Host,
   224→    ) -> Result<(Host, DispatchLayer), DispatchError> {
   225→        // A host should not book frames if its allocation is at or above its limit,
   226→        // but checking the limit before each frame is too costly. The tradeoff is
   227→        // to check the allocation state before entering the frame booking loop,
   228→        // with these there's a risk the allocation will go above burst, but not by
   229→        // a great margin as each loop only runs for a limited number of frames
   230→        // (see config queue.dispatch_frames_per_layer_limit)
   231→        let mut allocation_capacity = host.alloc_available_cores;
   232→        let allocation_name = host.alloc_name.clone();
   233→        let mut last_host_version = host;
   234→
   235→        let allocation_service = allocation_service().await.map_err(|err| {
   236→            DispatchError::Failure(err.wrap_err("Allocation Service is not available"))
   237→        })?;
   238→        // Use a closure for this validation to reduce the number of arguments that would be passed
   239→        // to dispatch_virtual_proc.
   240→        let is_subscription_bookable = |cores_requested| {
   241→            matches!(allocation_service.get_subscription(&allocation_name, &layer.show_id),
   242→                Some(subscription) if subscription.bookable(&cores_requested)
   243→            )
   244→        };
   245→
   246→        // Deliberately cloning the layer to avoid requiring a mutable reference
   247→        let mut layer = layer.clone();
   248→        let mut last_error = None;
   249→        let mut non_retrieable_frames = Vec::new();
   250→
   251→        // Use an unique id for all logs on this dispatch
   252→        let dispatch_id = Uuid::new_v4();
   253→
   254→        for frame in &layer.frames {
   255→            let frame_str = format!("{}", frame);
   256→
   257→            let (virtual_proc, updated_host) = match Self::consume_host_virtual_resources(
   258→                frame,
   259→                &last_host_version,
   260→                CONFIG.queue.memory_stranded_threshold,
   261→            )
   262→            .await
   263→            {
   264→                Ok(result) => result,
   265→                Err(VirtualProcError::HostResourcesExtinguished(msg)) => {
   266→                    debug!(
   267→                        "({dispatch_id}) Host resourse extinguished for {}. {}",
   268→                        last_host_version, msg
   269→                    );
   270→                    break;
   271→                }
   272→            };
   273→
   274→            debug!(
   275→                "({dispatch_id}) Host {} will have {} cores available after update",
   276→                updated_host.id, updated_host.idle_cores
   277→            );
   278→
   279→            // Each proc should run on its own transaction
   280→            let mut proc_transaction = begin_transaction()
   281→                .await
   282→                .map_err(DispatchError::DbFailure)?;
   283→
   284→            // Before dispatching, confirm the layer still has limits
   285→            if !self
   286→                .layer_dao
   287→                .check_limits(&mut proc_transaction, &layer)
   288→                .await
   289→                .map_err(DispatchError::DbFailure)?
   290→            {
   291→                proc_transaction
   292→                    .rollback()
   293→                    .await
   294→                    .map_err(DispatchError::DbFailure)?;
   295→                info!("({dispatch_id}) Skiping layer {}, reached limits", layer);
   296→
   297→                // Skip the entire layer
   298→                break;
   299→            }
