   401→        if !non_retrieable_frames.is_empty() {
   402→            layer.drain_frames(non_retrieable_frames);
   403→        }
   404→
   405→        if let Some(error) = last_error {
   406→            warn!("Wasn't able to dispatch all frames: {:?}", error)
   407→        }
   408→        Ok((last_host_version, layer))
   409→    }
