            .map_err(DispatchError::DbFailure)?;

        // Update the in-memory subscription cache and enqueue the delta for
        // the next background flush to the subscription table.
        allocation_service.record_booking(
            booking_show_id,
            booking_alloc_id,
            &booking_alloc_name,
            booking_core_delta,
            booking_gpu_delta,
